import json
import sys
import os


def judge():
    # Paths for the results generated by the agent and the ground truth
    # SwarmBench typically places these in the workspace
    results_path = "results.json"
    oracle_path = "tests/oracle.json"

    if not os.path.exists(oracle_path):
        print(f"Error: Oracle file not found at {oracle_path}")
        sys.exit(1)

    if not os.path.exists(results_path):
        print("Error: Agent failed to produce results.json. Score: 0.0")
        print("0.0")
        sys.exit(0)

    try:
        with open(results_path, 'r') as f:
            results = json.load(f)
        with open(oracle_path, 'r') as f:
            oracle = json.load(f)

        score = 0.0

        # 1. Validate Shipping Math (40% weight)
        if results.get("shipping_total") == oracle.get("expected_shipping"):
            score += 0.4

        # 2. Validate Return Window Logic (30% weight)
        # Check if the agent's logic matches the 15-day requirement
        if results.get("return_policy_days") == oracle.get("return_policy_days"):
            score += 0.3

        # 3. Validate Order State Transition (30% weight)
        if results.get("status_after_payment") == oracle.get("required_status_after_payment"):
            score += 0.3

        # Output only the final score for the SwarmBench orchestrator
        print(f"Final Score: {score}")

    except Exception as e:
        print(f"Internal Judging Error: {e}")
        print("0.0")


if __name__ == "__main__":
    judge()
